  17→// ── Bundled font setup for Sharp/librsvg SVG text rendering ──
  18→const __filename = fileURLToPath(import.meta.url);
  19→const __dirname = dirname(__filename);
  20→const FONT_DIR = join(__dirname, '.fonts');
  21→const FONT_PATH = join(FONT_DIR, 'DejaVuSans.ttf');
  22→const FONT_BOLD_PATH = join(FONT_DIR, 'DejaVuSans-Bold.ttf');
  23→let fontsReady = false;
  24→
  25→async function ensureShareFonts() {
  26→    if (fontsReady) return;
  27→    try {
  28→        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
  29→
  30→        const downloads = [];
  31→        if (!existsSync(FONT_PATH)) {
  32→            downloads.push(
  33→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
  34→                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  35→                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
  36→            );
  37→        }
  38→        if (!existsSync(FONT_BOLD_PATH)) {
  39→            downloads.push(
  40→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
  41→                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  42→                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
  43→            );
  44→        }
  45→        if (downloads.length) await Promise.all(downloads);
  46→
  47→        fontsReady = true;
  48→        console.log('Share fonts ready:', FONT_DIR);
  49→    } catch (err) {
  50→        console.error('Failed to setup share fonts:', err?.message || err);
  51→    }
  52→}
