  84→const metricsState = {
  85→    startedAt: new Date().toISOString(),
  86→    requests: 0,
  87→    responses: 0,
  88→    inFlight: 0,
  89→    bytesSent: 0,
  90→    statusBuckets: {
  91→        '2xx': 0,
  92→        '3xx': 0,
  93→        '4xx': 0,
