 127→const classifyStatusBucket = (statusCode) => {
 128→    if (statusCode >= 200 && statusCode < 300) return '2xx';
 129→    if (statusCode >= 300 && statusCode < 400) return '3xx';
 130→    if (statusCode >= 400 && statusCode < 500) return '4xx';
 131→    if (statusCode >= 500 && statusCode < 600) return '5xx';
 132→    return 'other';
 133→};
