 135→const normalizeWhitespace = (value) => String(value ?? '')
 136→    .replace(/\s+/g, ' ')
 137→    .trim();
 138→
 139→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 140→    const normalized = normalizeWhitespace(value);
 141→    if (!normalized) return '';
 142→    if (normalized.length <= maxLength) return normalized;
 143→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 144→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 145→};
