 155→const getRequestOrigin = (req) => {
 156→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 157→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 158→    const host = forwardedHost || req.get('host') || '';
 159→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 160→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 161→        ? forwardedProto
 162→        : requestProtocol === 'http' || requestProtocol === 'https'
 163→            ? requestProtocol
 164→            : 'https';
 165→
 166→    if (!host) {
 167→        return SITE_URL;
 168→    }
 169→
 170→    return `${protocol}://${host}`;
 171→};
