 173→const pickFirstNonEmptyString = (...values) => {
 174→    for (const value of values) {
 175→        if (typeof value === 'string') {
 176→            const trimmed = value.trim();
 177→            if (trimmed) return trimmed;
 178→        }
 179→    }
 180→    return '';
 181→};
