 183→const parseImageDimension = (value) => {
 184→    const parsed = Number(value);
 185→    if (!Number.isFinite(parsed)) return undefined;
 186→    return parsed;
 187→};
 188→
 189→const imageFromNodeLike = (nodeLike) => {
 190→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 191→
 192→    const src = pickFirstNonEmptyString(
 193→        nodeLike.src,
 194→        nodeLike.url,
 195→        nodeLike.image_url,
 196→        nodeLike.imageUrl,
 197→        nodeLike?.payload?.src,
 198→        nodeLike?.data?.src
 199→    );
 200→    if (!src) return null;
 201→
 202→    return {
 203→        src,
 204→        width: parseImageDimension(nodeLike.width),
 205→        height: parseImageDimension(nodeLike.height),
 206→    };
 207→};
