 363→const isSafeRemoteImageUrl = (imageUrl) => {
 364→    try {
 365→        const parsed = new URL(imageUrl);
 366→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 367→            return false;
 368→        }
 369→
 370→        const hostname = parsed.hostname.toLowerCase();
 371→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 372→            return false;
 373→        }
 374→
 375→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 376→            return false;
 377→        }
 378→
 379→        return true;
 380→    } catch {
 381→        return false;
 382→    }
 383→};
