 430→const fetchRemoteImageBuffer = async (imageUrl) => {
 431→    const controller = new AbortController();
 432→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 433→
 434→    try {
 435→        const response = await fetch(imageUrl, {
 436→            method: 'GET',
 437→            redirect: 'follow',
 438→            signal: controller.signal,
 439→            headers: {
 440→                Accept: 'image/*,*/*;q=0.8',
 441→                'Accept-Encoding': 'identity',
 442→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 443→            },
 444→        });
 445→
 446→        if (!response.ok) {
 447→            throw new Error(`upstream image status ${response.status}`);
 448→        }
 449→
 450→        const finalUrl = response.url || imageUrl;
 451→        if (!isSafeRemoteImageUrl(finalUrl)) {
 452→            throw new Error('upstream redirected to unsafe url');
 453→        }
 454→
 455→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 456→        if (!contentType.startsWith('image/')) {
 457→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 458→        }
 459→        if (contentType.includes('image/svg')) {
 460→            throw new Error('svg images are not used for share previews');
 461→        }
 462→
 463→        const headerContentLength = Number(response.headers.get('content-length'));
 464→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 465→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 466→        }
 467→
 468→        const arrayBuffer = await response.arrayBuffer();
 469→        const buffer = Buffer.from(arrayBuffer);
 470→
 471→        if (!buffer.length) {
 472→            throw new Error('upstream image is empty');
 473→        }
 474→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 475→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 476→        }
 477→
 478→        return {
 479→            buffer,
 480→            contentType,
 481→            byteLength: buffer.length,
 482→            finalUrl,
 483→        };
 484→    } finally {
 485→        clearTimeout(timeout);
 486→    }
 487→};
