 523→const corsOptions = {
 524→    origin: ['https://iskrib.com', 'https://iskrib-v3-client-side.onrender.com', 'http://localhost:5173'],
 525→    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
 526→    allowedHeaders: ['Content-Type', 'Authorization'],
 527→    credentials: true,
 528→    maxAge: 60 * 60 * 24
 529→};
 530→
 531→app.use(cors(corsOptions));
 532→app.use(compression({ threshold: 1024 }));
 533→app.disable("x-powered-by");
 534→app.use(
 535→    helmet({
 536→        contentSecurityPolicy: false,
 537→        crossOriginEmbedderPolicy: false,
 538→    })
 539→);
 540→
 541→app.use((req, res, next) => {
 542→    metricsState.requests += 1;
 543→    metricsState.inFlight += 1;
 544→
 545→    const startNs = process.hrtime.bigint();
 546→    let byteCount = 0;
 547→
 548→    const originalWrite = res.write.bind(res);
 549→    const originalEnd = res.end.bind(res);
 550→
 551→    res.write = (chunk, encoding, callback) => {
 552→        if (chunk) {
 553→            byteCount += Buffer.isBuffer(chunk)
 554→                ? chunk.length
 555→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 556→        }
 557→        return originalWrite(chunk, encoding, callback);
 558→    };
 559→
 560→    res.end = (chunk, encoding, callback) => {
 561→        if (chunk) {
 562→            byteCount += Buffer.isBuffer(chunk)
 563→                ? chunk.length
 564→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 565→        }
 566→        return originalEnd(chunk, encoding, callback);
 567→    };
 568→
 569→    res.on('finish', () => {
 570→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 571→        metricsState.responses += 1;
 572→        metricsState.bytesSent += byteCount;
 573→
 574→        const statusBucket = classifyStatusBucket(res.statusCode);
 575→        metricsState.statusBuckets[statusBucket] += 1;
 576→
 577→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 578→        const routeTemplate = req.route?.path
 579→            ? `${req.baseUrl || ''}${req.route.path}`
 580→            : req.path;
 581→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 582→
 583→        let routeStat = metricsState.routeStats.get(routeKey);
 584→        if (!routeStat) {
 585→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 586→                return;
 587→            }
 588→
 589→            routeStat = {
 590→                count: 0,
 591→                totalDurationMs: 0,
 592→                maxDurationMs: 0,
 593→                bytesSent: 0,
 594→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 595→            };
 596→            metricsState.routeStats.set(routeKey, routeStat);
 597→        }
 598→
 599→        routeStat.count += 1;
 600→        routeStat.totalDurationMs += durationMs;
 601→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 602→        routeStat.bytesSent += byteCount;
 603→        routeStat.statusBuckets[statusBucket] += 1;
 604→    });
 605→
 606→    next();
 607→});
 608→
 609→app.use((req, res, next) => {
 610→    if (req.method !== "GET") {
 611→        return next();
 612→    }
 613→
 614→    const normalizedPath = normalizeApiPath(req.path);
 615→    const isPersonalized = isPersonalizedGetRequest(req);
 616→
 617→    if (!isPersonalized && isCacheablePublicPath(normalizedPath)) {
 618→        res.set("Cache-Control", PUBLIC_CACHE_CONTROL_VALUE);
 619→    } else if (isPersonalized) {
 620→        res.set("Cache-Control", PRIVATE_NO_STORE_CACHE_CONTROL);
 621→    }
 622→
 623→    return next();
 624→});
 625→
 626→app.use(express.json({ limit: "2mb" }));
 627→app.use(express.urlencoded({extended: true, limit: "2mb", parameterLimit: 1000}));
