 629→// ── Profile share route: composite OG image for social media ──
 630→app.get('/share/u/:username/image', async (req, res) => {
 631→    const { username } = req.params;
 632→    await ensureShareFonts();
 633→
 634→    try {
 635→        const result = await getUserByUsernameService(username);
 636→        const user = result?.userData?.[0];
 637→        if (!user) {
 638→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 639→        }
 640→
 641→        const displayName = normalizeWhitespace(user.name) || username;
 642→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 643→        const bio = toPreviewText(user.bio || '', 120);
 644→
 645→        // ── Fetch background image ──
 646→        let bgBuffer = null;
 647→        const bgStyle = user.background || {};
 648→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 649→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 650→            : null;
 651→        const bgImageUrl = bgImageMatch?.[1];
 652→
 653→        if (bgImageUrl) {
 654→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 655→            if (bgEval.ok && bgEval.resolvedUrl) {
 656→                try {
 657→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 658→                    bgBuffer = remote.buffer;
 659→                } catch { /* use fallback gradient */ }
 660→            }
 661→        }
 662→
 663→        // ── Base layer: background or dark gradient ──
 664→        let baseLayer;
 665→        if (bgBuffer) {
 666→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 667→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 668→                .toBuffer();
 669→        } else {
 670→            // Use profile's solid background color if available, otherwise dark fallback
 671→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 672→                ? bgStyle.background.trim()
 673→                : null;
 674→            const gradientSvg = solidColor
 675→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 676→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 677→                </svg>`
 678→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 679→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 680→                        <stop offset="0%" stop-color="#1a1a2e"/>
 681→                        <stop offset="100%" stop-color="#16213e"/>
 682→                    </linearGradient></defs>
 683→                    <rect width="100%" height="100%" fill="url(#g)"/>
 684→                </svg>`;
 685→            baseLayer = await sharp(Buffer.from(gradientSvg))
 686→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 687→                .png()
 688→                .toBuffer();
 689→        }
 690→
 691→        // ── Dark overlay for text readability ──
 692→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 693→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 694→        </svg>`;
 695→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 696→
 697→        // ── Circular avatar ──
 698→        let avatarComposite = null;
 699→        const avatarSize = 180;
 700→        const avatarUrl = user.image_url;
 701→        if (avatarUrl) {
 702→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 703→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 704→                try {
 705→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 706→                    const circleMask = Buffer.from(
 707→                        `<svg width="${avatarSize}" height="${avatarSize}">
 708→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 709→                        </svg>`
 710→                    );
 711→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 712→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 713→                        .png()
 714→                        .toBuffer();
 715→                    const circularAvatar = await sharp(resizedAvatar)
 716→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 717→                        .png()
 718→                        .toBuffer();
 719→                    avatarComposite = circularAvatar;
 720→                } catch { /* skip avatar */ }
 721→            }
 722→        }
 723→
 724→        // ── Compose all layers ──
 725→        const composites = [
 726→            { input: overlayBuffer, top: 0, left: 0 },
 727→        ];
 728→
 729→        if (avatarComposite) {
 730→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 731→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 732→        }
 733→
 734→        const finalImage = await sharp(baseLayer)
 735→            .composite(composites)
 736→            .jpeg({ quality: 82, mozjpeg: true })
 737→            .toBuffer();
 738→
 739→        res.set('Content-Type', 'image/jpeg');
 740→        res.set('Cache-Control', 'public, max-age=3600');
 741→        return res.send(finalImage);
 742→    } catch (err) {
 743→        console.error('profile share image route error:', err?.message || err);
 744→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 745→    }
 746→});
