export const checkHottestPostTracker = async () => {
    const now = new Date();
    const monthKey = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, '0')}`;
    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));

    const {data: journals, error: journalsError} = await supabase
        .from('journals')
        .select(JOURNAL_WITH_COUNTS_SELECT)
        .eq('privacy', 'public')
        .gte('created_at', monthStartUtc.toISOString())
        .lt('created_at', nextMonthStartUtc.toISOString());

    if(journalsError){
        console.error('hottest tracker: error fetching journals:', journalsError.message);
        return;
    }

    if(!journals || journals.length === 0){
        return;
    }

    const scored = journals.map((journal) => {
        const hotScore = scoreJournalHotness(journal);
        return { ...journal, hot_score: hotScore };
    });

    scored.sort((a, b) => {
        const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
        if(scoreDiff !== 0) return scoreDiff;
        const dateDiff = new Date(b.created_at || 0) - new Date(a.created_at || 0);
        if(dateDiff !== 0) return dateDiff;
        return (b.id || 0) - (a.id || 0);
    });

    const topPost = scored[0];
    const newJournalId = topPost.id;
    const newUserId = topPost.users?.id || topPost.user_id;
    const newHotScore = topPost.hot_score || 0;

    const {data: existing, error: selectError} = await supabase
        .from('hottest_tracker')
        .select('*')
        .eq('month_key', monthKey)
        .maybeSingle();

    if(selectError){
        console.error('hottest tracker select error:', selectError.message);
        return;
    }

    if(existing && existing.journal_id === newJournalId){
        return;
    }

    // Notify old #1 that they've been replaced
    if(existing){
        const {error: replacedNotifError} = await supabase
            .from('notifications')
            .insert({
                sender_id: existing.user_id,
                receiver_id: existing.user_id,
                journal_id: existing.journal_id,
                type: 'hottest_post_replaced',
                read: false,
            });
        if(replacedNotifError){
            console.error('hottest replaced notification error:', replacedNotifError.message);
        }
    }

    // Upsert new #1
    const {error: upsertError} = await supabase
        .from('hottest_tracker')
        .upsert({
            month_key: monthKey,
            journal_id: newJournalId,
            user_id: newUserId,
            hot_score: newHotScore,
            updated_at: new Date().toISOString(),
        }, {onConflict: 'month_key'});

    if(upsertError){
        console.error('hottest tracker upsert error:', upsertError.message);
        return;
    }

    // Notify new #1
    const {error: newNotifError} = await supabase
        .from('notifications')
        .insert({
            sender_id: newUserId,
            receiver_id: newUserId,
            journal_id: newJournalId,
            type: 'hottest_post',
            read: false,
        });
    if(newNotifError){
        console.error('hottest new notification error:', newNotifError.message);
    } else {
        console.log('hottest tracker: new #1 post', newJournalId);
    }
}

export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
    }

    const parsedLimit = parseInt(limit);
    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
    const isNewest = normalizedSort === 'newest';
